package com.nullPointerSociety.elfogon.ui.screens.client.recipes.detailsimport android.annotation.SuppressLintimport android.os.Buildimport android.util.Logimport androidx.annotation.RequiresApiimport androidx.compose.foundation.layout.PaddingValuesimport androidx.compose.foundation.layout.fillMaxSizeimport androidx.compose.foundation.layout.paddingimport androidx.compose.foundation.lazy.LazyColumnimport androidx.compose.foundation.lazy.LazyListStateimport androidx.compose.material3.MaterialThemeimport androidx.compose.material3.Textimport androidx.compose.runtime.Composableimport androidx.compose.runtime.MutableStateimport androidx.compose.ui.Modifierimport androidx.compose.ui.tooling.preview.Previewimport androidx.compose.ui.unit.dpimport androidx.lifecycle.viewmodel.compose.viewModelimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.Ingredientsimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.RecipeDetailsTitleimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.RecipeImgimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.RecipeSummaryimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.Stepsimport com.nullPointerSociety.elfogon.ui.navigation.SavedRecipesScreenNav@RequiresApi(Build.VERSION_CODES.N)@Composablefun RecipeDetailsScreen(    id: String,    requester: String,    onBack: () -> Unit,    @SuppressLint("ModifierParameter") modifier: Modifier = Modifier,    titleScreen: MutableState<String>,    scrollState: LazyListState) {    val detailsScreenViewModel: RecipeDetailsViewModel =        viewModel(factory = RecipeDetailsViewModel.Factory)    val detailRecipe = when (requester) {        SavedRecipesScreenNav::class.qualifiedName -> detailsScreenViewModel.getRecipeSavedById(id)            ?: detailsScreenViewModel.getSystemRecipeById(id)        else -> {            detailsScreenViewModel.getRecipeById(id) ?: detailsScreenViewModel.getSystemRecipeById(                id            )        }    }    titleScreen.value = detailRecipe?.title.toString()    Log.d("Recipe Details", "Recipe ID: ${detailRecipe?.id} and Title: ${detailRecipe?.title}")    LazyColumn(        state = scrollState,        contentPadding = PaddingValues(bottom = 140.dp),        modifier = modifier            .fillMaxSize()    ) {        item {            RecipeDetailsTitle(detailRecipe?.title, detailRecipe?.readyInMinutes)        }        item {            RecipeImg(detailRecipe?.image, detailRecipe?.title)        }        item {            RecipeSummary(detailRecipe?.summary)        }        item {            Ingredients(detailRecipe?.extendedIngredients ?: emptyList())        }        item {            Text(                text = "Steps you need to follow to prepare this recipe!",                style = MaterialTheme.typography.titleLarge,                modifier = Modifier.padding(horizontal = 20.dp, vertical = 25.dp)            )            Steps(detailRecipe?.analyzedInstructions ?: emptyList())        }    }}